#!/usr/bin/env bash
# scripts/test-vm.sh — Run VM golden tests in interp and/or JIT mode.
#
# Each golden test directory must contain:
#   source.zbc          — compiled bytecode (generated by regen-golden-tests.sh)
#   expected_output.txt — expected stdout
#
# Usage:
#   ./scripts/test-vm.sh              # run both interp and jit
#   ./scripts/test-vm.sh interp       # interp only
#   ./scripts/test-vm.sh jit          # jit only
#
# Exit code: 0 if all selected tests pass, 1 otherwise.

set -euo pipefail

# Resolve project root regardless of working directory
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
ROOT="$SCRIPT_DIR/.."
cd "$ROOT"

RUNTIME_MANIFEST="src/runtime/Cargo.toml"
# Golden roots: VM-only cases live under src/runtime/tests/golden/run; stdlib-
# specific cases live alongside their library at src/libraries/<lib>/tests/golden.
GOLDEN_GLOBS=(
    "src/runtime/tests/golden/run/*/"
    "src/libraries/"*"/tests/golden/"*"/"
)
MODES=("interp" "jit")

if [ $# -ge 1 ]; then
    MODES=("$1")
fi

# Build once before running tests
echo "Building VM..."
cargo build -q --manifest-path "$RUNTIME_MANIFEST"
echo ""

OVERALL_PASS=0
OVERALL_FAIL=0

for MODE in "${MODES[@]}"; do
    echo "══════════════════════════════════════"
    echo " Mode: $MODE"
    echo "══════════════════════════════════════"

    PASS=0
    FAIL=0
    FAILURES=()

    # Collect every golden case dir matching any configured glob.
    DIRS=()
    for glob in "${GOLDEN_GLOBS[@]}"; do
        for d in $glob; do
            [ -d "$d" ] && DIRS+=("$d")
        done
    done

    for dir in "${DIRS[@]}"; do
        name=$(basename "$dir")
        artifact="$dir/source.zbc"
        expected="$dir/expected_output.txt"

        [ -f "$artifact" ] && [ -f "$expected" ] || continue

        actual=$(cargo run -q --manifest-path "$RUNTIME_MANIFEST" -- "$artifact" --mode "$MODE" 2>&1) || true

        if [ "$actual" = "$(cat "$expected")" ]; then
            PASS=$((PASS + 1))
        else
            FAIL=$((FAIL + 1))
            FAILURES+=("$name")
            echo "  FAIL: $name"
            echo "    expected: $(head -1 "$expected")"
            echo "    actual:   $(echo "$actual" | head -1)"
        fi
    done

    echo ""
    echo "  Result: $PASS passed, $FAIL failed"
    echo ""

    OVERALL_PASS=$((OVERALL_PASS + PASS))
    OVERALL_FAIL=$((OVERALL_FAIL + FAIL))
done

echo "══════════════════════════════════════"
echo " Total: $OVERALL_PASS passed, $OVERALL_FAIL failed"
echo "══════════════════════════════════════"

[ "$OVERALL_FAIL" -eq 0 ]
